def _validate_message_against_nonce(address: str, message: str, expected_nonce: str) -> Tuple[int, int]:
    if f"Nonce: {expected_nonce}" not in message:
        raise HTTPException(status_code=400, detail="Message nonce mismatch")
    # Soft checks for domain and address presence
    if DOMAIN not in message:
        raise HTTPException(status_code=400, detail="Message domain mismatch")
    if _normalize_address(address) not in message:
        raise HTTPException(status_code=400, detail="Message address mismatch")

    issued_at = None
    exp_at = None
    for line in message.splitlines():
        if line.startswith("Issued At: "):
            issued_at = line[len("Issued At: "):].strip()
        if line.startswith("Expiration Time: "):
            exp_at = line[len("Expiration Time: "):].strip()

    def _parse_ts(s: str) -> int:
        try:
            # Expect Zulu format like 2024-01-01T00:00:00Z
            return int(time.mktime(time.strptime(s, "%Y-%m-%dT%H:%M:%SZ")))
        except Exception:
            return 0

    issued_ts = _parse_ts(issued_at) if issued_at else 0
    exp_ts = _parse_ts(exp_at) if exp_at else 0

    now = _now()
    if issued_ts and issued_ts > now + MAX_CLOCK_SKEW_SECONDS:
        raise HTTPException(status_code=400, detail="Message issued_at is in the future")
    if exp_ts and exp_ts <= now:
        raise HTTPException(status_code=400, detail="Message expired")
    return issued_ts, exp_ts


