    rec = _NONCES.get(claimed.lower())
    if not rec:
        raise HTTPException(status_code=400, detail="No active nonce for address")
    if rec["expires_at"] <= _now():
        _NONCES.pop(claimed.lower(), None)
        raise HTTPException(status_code=400, detail="Nonce expired")

